import{c as t,Q as a,j as i,m as n}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse(`{"title":"Dive into Claude Code: The Design Space of Today's and Future AI Agent Systems","description":"","frontmatter":{"title":"Dive into Claude Code: The Design Space of Today's and Future AI Agent Systems","authors":"Jiacheng Liu, Xiaohan Zhao, Xinyi Shang, Zhiqiang Shen","published":"2026-04-14T00:00:00.000Z","source":"https://arxiv.org/abs/2604.14228"},"headers":[],"relativePath":"research/agent-harness/references/2026-04-14-dive-into-claude-code-design-space-2604-14228.md","filePath":"research/agent-harness/references/2026-04-14-dive-into-claude-code-design-space-2604-14228.md","lastUpdated":1779901665000}`),s={name:"research/agent-harness/references/2026-04-14-dive-into-claude-code-design-space-2604-14228.md"};function r(o,e,l,d,c,u){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="dive-into-claude-code-the-design-space-of-today-s-and-future-ai-agent-systems" tabindex="-1">Dive into Claude Code: The Design Space of Today&#39;s and Future AI Agent Systems <a class="header-anchor" href="#dive-into-claude-code-the-design-space-of-today-s-and-future-ai-agent-systems" aria-label="Permalink to &quot;Dive into Claude Code: The Design Space of Today&#39;s and Future AI Agent Systems&quot;">​</a></h1><p><strong>Authors</strong>: Jiacheng Liu, Xiaohan Zhao, Xinyi Shang, Zhiqiang Shen <strong>Published</strong>: April 14, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2604.14228" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.14228</a><strong>arXiv ID</strong>: 2604.14228 <strong>Categories</strong>: cs.SE, cs.AI, cs.HC</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Comprehensive architectural analysis of Claude Code, Anthropic&#39;s agentic coding tool, by examining publicly available TypeScript source code. Rather than merely describing features, the authors trace design decisions from underlying human values through specific implementation choices. Maps 98.4% of production codebase as operational infrastructure, only 1.6% as AI logic. Compares with OpenClaw and outlines six design directions for future systems.</p><hr><h2 id="five-foundational-values" tabindex="-1">Five Foundational Values <a class="header-anchor" href="#five-foundational-values" aria-label="Permalink to &quot;Five Foundational Values&quot;">​</a></h2><p>The architecture reflects five core commitments:</p><ol><li><strong>Human Decision Authority</strong> — Users retain ultimate control through informed observation, approval/rejection capabilities, and auditable records</li><li><strong>Safety, Security, and Privacy</strong> — Protection mechanisms operate independently of user vigilance, addressing overeager behavior and prompt injection</li><li><strong>Reliable Execution</strong> — Multi-turn coherence with environmental feedback at each step</li><li><strong>Capability Amplification</strong> — Enabling qualitatively new workflows (approximately 27% of tasks wouldn&#39;t be attempted otherwise)</li><li><strong>Contextual Adaptability</strong> — Configuration at multiple levels with trust trajectories improving over time</li></ol><hr><h2 id="architectural-components" tabindex="-1">Architectural Components <a class="header-anchor" href="#architectural-components" aria-label="Permalink to &quot;Architectural Components&quot;">​</a></h2><p>Seven functional elements:</p><ul><li>User interfaces (CLI, IDE, SDK)</li><li>Shared agent loop</li><li>Permission system</li><li>Tool pool</li><li>State and persistence mechanisms</li><li>Execution environment</li></ul><h3 id="five-layer-subsystem-structure" tabindex="-1">Five-Layer Subsystem Structure <a class="header-anchor" href="#five-layer-subsystem-structure" aria-label="Permalink to &quot;Five-Layer Subsystem Structure&quot;">​</a></h3><p><strong>Surface layer</strong>: Multiple entry points (CLI, IDE, SDK) converging on identical logic</p><p><strong>Core layer</strong>: Simple reactive loop with five-stage context management pipeline</p><p><strong>Safety/action layer</strong>: Deny-first permission evaluation, ML-based classifier, hooks, tools, sandboxing, subagent spawning</p><p><strong>State layer</strong>: CLAUDE.md hierarchy, append-only transcripts, memory mechanisms</p><p><strong>Backend layer</strong>: Shell execution, filesystem operations, MCP connections, tool implementations</p><hr><h2 id="the-98-4-infrastructure-ratio" tabindex="-1">The 98.4% Infrastructure Ratio <a class="header-anchor" href="#the-98-4-infrastructure-ratio" aria-label="Permalink to &quot;The 98.4% Infrastructure Ratio&quot;">​</a></h2><p>Claude Code v2.1.88 codebase decomposition:</p><ul><li><strong>98.4% = operational infrastructure</strong>: context management, tool routing, error recovery, session management</li><li><strong>1.6% = AI reasoning logic</strong>: actual model calls</li></ul><blockquote><p>&quot;98.4% of Claude Code&#39;s production codebase is operational infrastructure—context management, routing, and recovery—while only 1.6% is AI reasoning logic.&quot;</p></blockquote><p>This ratio validates that harness engineering, not prompt engineering or model selection, is the primary determinant of agent system quality.</p><hr><h2 id="key-design-decisions" tabindex="-1">Key Design Decisions <a class="header-anchor" href="#key-design-decisions" aria-label="Permalink to &quot;Key Design Decisions&quot;">​</a></h2><h3 id="permission-architecture" tabindex="-1">Permission Architecture <a class="header-anchor" href="#permission-architecture" aria-label="Permalink to &quot;Permission Architecture&quot;">​</a></h3><p>Seven independent safety layers operating in parallel:</p><ol><li>Pre-filtering (deny-list patterns)</li><li>Deny-first rules (explicit block rules)</li><li>Permission modes (plan/auto/bypassPermissions)</li><li>ML classifier (behavioral evaluation)</li><li>Shell sandboxing (execution isolation)</li><li>Non-restoration on resume (audit continuity)</li><li>Hooks (programmatic interception)</li></ol><p>Any single layer can block execution. The system implements graduated autonomy:</p><ul><li><strong>plan</strong>: user approves plans first</li><li><strong>auto</strong>: ML evaluation</li><li><strong>bypassPermissions</strong>: minimal prompting</li></ul><h3 id="context-management-pipeline" tabindex="-1">Context Management Pipeline <a class="header-anchor" href="#context-management-pipeline" aria-label="Permalink to &quot;Context Management Pipeline&quot;">​</a></h3><p>The binding resource constraint is the context window. Five sequential shapers manage pressure before each model call:</p><table tabindex="0"><thead><tr><th>Stage</th><th>Mechanism</th><th>Trigger</th></tr></thead><tbody><tr><td>1</td><td>Budget reduction</td><td>Caps individual tool outputs</td></tr><tr><td>2</td><td>Snip</td><td>Removes older history</td></tr><tr><td>3</td><td>Microcompact</td><td>Fine-grained compression</td></tr><tr><td>4</td><td>Context collapse</td><td>Read-time projections</td></tr><tr><td>5</td><td>Auto-compact</td><td>Semantic summarization (last resort)</td></tr></tbody></table><h3 id="extensibility-mechanisms" tabindex="-1">Extensibility Mechanisms <a class="header-anchor" href="#extensibility-mechanisms" aria-label="Permalink to &quot;Extensibility Mechanisms&quot;">​</a></h3><p>Four complementary mechanisms at different context costs:</p><table tabindex="0"><thead><tr><th>Mechanism</th><th>Cost</th><th>Use Case</th></tr></thead><tbody><tr><td>MCP servers</td><td>Medium</td><td>External tool integration</td></tr><tr><td>Plugins</td><td>Medium</td><td>Reusable component packages</td></tr><tr><td>Skills</td><td>Low</td><td>Domain-specific instruction injection</td></tr><tr><td>Hooks</td><td>Zero runtime</td><td>Execution lifecycle interception (27 event types)</td></tr></tbody></table><h3 id="subagent-delegation" tabindex="-1">Subagent Delegation <a class="header-anchor" href="#subagent-delegation" aria-label="Permalink to &quot;Subagent Delegation&quot;">​</a></h3><p>Subagents operate in isolated context windows with separate transcripts (sidechains). Return only summaries to parents rather than full conversation histories. Permission escalation flows through &quot;bubble&quot; mode.</p><hr><h2 id="thirteen-design-principles" tabindex="-1">Thirteen Design Principles <a class="header-anchor" href="#thirteen-design-principles" aria-label="Permalink to &quot;Thirteen Design Principles&quot;">​</a></h2><p>Recurring principles operationalizing the five values:</p><ol><li>Deny-first with human escalation</li><li>Graduated trust spectrum reflecting relationship evolution</li><li>Defense in depth via layered mechanisms</li><li>Externalized programmable policy</li><li>Context as scarce resource with progressive management</li><li>Append-only durable state (auditable history)</li><li>Minimal scaffolding, maximal operational harness</li><li>Values over rules (contextual judgment within deterministic guardrails)</li><li>Composable multi-mechanism extensibility</li><li>Reversibility-weighted risk assessment</li><li>Transparent file-based configuration</li><li>Isolated subagent boundaries</li><li>Graceful recovery and resilience</li></ol><hr><h2 id="claude-code-vs-openclaw-comparison" tabindex="-1">Claude Code vs OpenClaw Comparison <a class="header-anchor" href="#claude-code-vs-openclaw-comparison" aria-label="Permalink to &quot;Claude Code vs OpenClaw Comparison&quot;">​</a></h2><p>Six comparative dimensions:</p><table tabindex="0"><thead><tr><th>Dimension</th><th>Claude Code</th><th>OpenClaw</th></tr></thead><tbody><tr><td>Deployment model</td><td>Closed-source, optimized harness</td><td>Open-source, portable</td></tr><tr><td>Trust architecture</td><td>Per-action evaluation</td><td>Perimeter-level access control</td></tr><tr><td>Agent runtime</td><td>CLI reactive loop</td><td>Embedded in gateway control plane</td></tr><tr><td>Extension mechanisms</td><td>MCP + Plugins + Skills + Hooks</td><td>Modular plugin system</td></tr><tr><td>Memory management</td><td>Prefix caching + auto-compact</td><td>Manual management</td></tr><tr><td>Multi-agent routing</td><td>Subagent sidechains</td><td>Gateway-level routing</td></tr></tbody></table><p>Same design questions yield different answers under different contexts. Neither is universally superior.</p><hr><h2 id="six-future-design-directions" tabindex="-1">Six Future Design Directions <a class="header-anchor" href="#six-future-design-directions" aria-label="Permalink to &quot;Six Future Design Directions&quot;">​</a></h2><ol><li><strong>Observability-evaluation gap</strong>: Silent failures where safety mechanisms work but produce undetected suboptimal results</li><li><strong>Cross-session persistence</strong>: Longitudinal colleague relationships and accumulated learning</li><li><strong>Harness boundary evolution</strong>: Expanding where, when, and with whom agents act</li><li><strong>Horizon scaling</strong>: From single sessions to sustained scientific programs</li><li><strong>Governance at scale</strong>: Oversight mechanisms for high-autonomy deployments</li><li><strong>Long-term capability preservation</strong>: Tension between short-term amplification and sustained human understanding</li></ol><hr><h2 id="running-example-traced-through-system" tabindex="-1">Running Example Traced Through System <a class="header-anchor" href="#running-example-traced-through-system" aria-label="Permalink to &quot;Running Example Traced Through System&quot;">​</a></h2><p>The paper traces &quot;Fix the failing test in auth.test.ts&quot; through all major subsystems:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input → Surface layer (CLI)</span></span>
<span class="line"><span>    → Core layer (reactive loop, context pipeline)</span></span>
<span class="line"><span>        → Safety/action layer (permission check, ML classifier)</span></span>
<span class="line"><span>            → Tool execution (bash, read, edit)</span></span>
<span class="line"><span>                → State layer (transcript append, memory update)</span></span>
<span class="line"><span>                    → Backend layer (filesystem ops)</span></span>
<span class="line"><span>                        → Model call (1.6% of system)</span></span>
<span class="line"><span>                            → Response rendering</span></span></code></pre></div><hr><h2 id="long-term-human-capability-concern" tabindex="-1">Long-Term Human Capability Concern <a class="header-anchor" href="#long-term-human-capability-concern" aria-label="Permalink to &quot;Long-Term Human Capability Concern&quot;">​</a></h2><p>The paper identifies an open tension: while the architecture substantially amplifies short-term programmer productivity, it offers limited explicit mechanisms supporting long-term human improvement, codebase coherence, or developer pipeline sustainability.</p><p>Empirical research documenting skill atrophy under AI assistance frames a critical question for future agent system design. This is identified as the most significant unresolved design challenge.</p><hr><h2 id="workspace-alignment-analysis" tabindex="-1">Workspace Alignment Analysis <a class="header-anchor" href="#workspace-alignment-analysis" aria-label="Permalink to &quot;Workspace Alignment Analysis&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Paper Claim</th><th>cc-workspace</th><th>Gap</th></tr></thead><tbody><tr><td>98.4% infrastructure ratio</td><td><code>.claude/</code> directory complexity &gt;&gt; AI logic</td><td>✅</td></tr><tr><td>Human Decision Authority</td><td>PreToolUse hooks + CLAUDE.md production red lines</td><td>✅</td></tr><tr><td>Contextual Adaptability</td><td>CLAUDE.md three-layer loading strategy</td><td>✅</td></tr><tr><td>Deny-first architecture</td><td><code>settings.json</code> permission modes</td><td>✅</td></tr><tr><td>Long-horizon state management</td><td><code>schemas/progress.schema.json</code></td><td>⚠️ Partial</td></tr><tr><td>Evaluation-integrated development</td><td><code>/deep-review</code> + healthcheck.sh (manual trigger)</td><td>⚠️ Partial</td></tr><tr><td>Cross-session persistence</td><td>Auto Memory (flat accumulation, no consolidation)</td><td>⚠️ Partial</td></tr></tbody></table><p>Integration targets: <code>ANTHROPIC-ALIGNMENT.md</code> §一 核心主張 + <code>HARNESS-CARD.md</code></p>`,64)])])}const m=t(s,[["render",r]]);export{h as __pageData,m as default};
